import{_ as i,o as a,c as r,ai as t}from"./chunks/framework.ampVZV4B.js";const d=JSON.parse('{"title":"第一阶段：大模型（LLM）入门与 Prompt 规划【效率优先】","description":"","frontmatter":{},"headers":[],"relativePath":"ai/llm-basics.md","filePath":"ai/llm-basics.md"}'),o={name:"ai/llm-basics.md"};function e(s,l,n,u,p,c){return a(),r("div",null,[...l[0]||(l[0]=[t('<h1 id="第一阶段-大模型-llm-入门与-prompt-规划【效率优先】" tabindex="-1">第一阶段：大模型（LLM）入门与 Prompt 规划【效率优先】 <a class="header-anchor" href="#第一阶段-大模型-llm-入门与-prompt-规划【效率优先】" aria-label="Permalink to “第一阶段：大模型（LLM）入门与 Prompt 规划【效率优先】”">​</a></h1><blockquote><p>这一篇专门帮你规划：<strong>如果你现在只是普通开发，希望先用好大模型提升效率</strong>，应该怎么学、学到什么程度算“够用”。</p></blockquote><hr><h2 id="_1-不同学习目的下-这一阶段的目标" tabindex="-1">1. 不同学习目的下，这一阶段的目标 <a class="header-anchor" href="#_1-不同学习目的下-这一阶段的目标" aria-label="Permalink to “1. 不同学习目的下，这一阶段的目标”">​</a></h2><ul><li><p><strong>目的 A：先用 AI 帮我写代码 / 查 bug / 总结文档</strong>（效率提升型）</p><ul><li>目标：会用 1～2 个主流模型（GPT / 通义等），会问问题、会写 Prompt。</li><li>输出物：能用模型帮你写 CRUD、改 bug、生成学习提纲和面试答案。</li></ul></li><li><p><strong>目的 B：想做一点“小工具”或副业产品</strong>（轻量产品型）</p><ul><li>目标：在 A 的基础上，会通过 API 调用模型，做简单 Web/命令行工具。</li><li>输出物：1～2 个真正能自己用的小工具（如：学习笔记总结器、面试问答助手）。</li></ul></li><li><p><strong>目的 C：以后可能向 AI 方向发展</strong>（长线型）</p><ul><li>目标：对不同模型（GPT/Qwen/LLaMA）和基本概念更熟悉，Prompt 能写得更专业。</li><li>输出物：一套属于自己的 Prompt 模板库 + 几个小 DEMO。</li></ul></li></ul><blockquote><p>对你现在的情况，<strong>A + B 就足够了</strong>，C 可以当作顺手积累。</p></blockquote><hr><h2 id="_2-建议学习顺序-按一周-两周来规划" tabindex="-1">2. 建议学习顺序（按一周～两周来规划） <a class="header-anchor" href="#_2-建议学习顺序-按一周-两周来规划" aria-label="Permalink to “2. 建议学习顺序（按一周～两周来规划）”">​</a></h2><h3 id="第一步-熟悉模型与控制台-0-5-天" tabindex="-1">第一步：熟悉模型与控制台（0.5 天） <a class="header-anchor" href="#第一步-熟悉模型与控制台-0-5-天" aria-label="Permalink to “第一步：熟悉模型与控制台（0.5 天）”">​</a></h3><ul><li>注册并熟悉 1～2 个平台： <ul><li>比如：ChatGPT / 通义千问 / 其他你常用的一个国内平台。</li></ul></li><li>在 Web 界面里刻意练习： <ul><li>用它帮你<strong>解释 Java/数据库 面试题</strong>。</li><li>让它根据你现在的项目，帮你写“自我介绍 + 项目包装”。</li></ul></li></ul><h3 id="第二步-系统学习-prompt-基本套路-1-2-天" tabindex="-1">第二步：系统学习 Prompt 基本套路（1～2 天） <a class="header-anchor" href="#第二步-系统学习-prompt-基本套路-1-2-天" aria-label="Permalink to “第二步：系统学习 Prompt 基本套路（1～2 天）”">​</a></h3><p>建议把下面这些“模板”写到你自己的文档中，反复用、反复改：</p><ul><li>角色 + 目标： <ul><li>“你是一个资深 Java 面试官，请帮我…”</li><li>“你是一个技术文档编辑，请帮我…”</li></ul></li><li>输入格式约束： <ul><li>“下面是我写的笔记，请你用 3 点总结 + 1 个举例…”</li></ul></li><li>输出格式约束： <ul><li>“输出用 Markdown 标题 + 列表，不要写废话。”</li></ul></li></ul><p><strong>练习方向：</strong></p><ul><li>针对你的 <code>docs</code> 里每个模块（Java、数据库、Redis、框架等），各设计 1～2 个 Prompt： <ul><li>“帮我根据这篇文档，出 5 道面试题并给出标准答案。”</li><li>“帮我把这篇内容改写成更口语化的面试回答。”</li></ul></li></ul><hr><h2 id="_3-api-调用层面的规划-偏目的-b-c" tabindex="-1">3. API 调用层面的规划（偏目的 B/C） <a class="header-anchor" href="#_3-api-调用层面的规划-偏目的-b-c" aria-label="Permalink to “3. API 调用层面的规划（偏目的 B/C）”">​</a></h2><p>如果你只是用网页聊天，可以先不看这一节；<br> 如果你想做点自己的小工具，可以按下面安排：</p><ul><li>第 1 步（1 天）：选一个语言栈（推荐你熟悉的 Java 或 JavaScript） <ul><li>看官方 “API Quickstart” 示例，照抄一遍。</li><li>改成从命令行读取输入，输出模型结果。</li></ul></li><li>第 2 步（1～2 天）：做一个最简小工具 <ul><li>例如：<strong>面试问答生成器</strong><ul><li>输入：一个知识点标题（如“事务隔离级别”）。</li><li>后端：调用 LLM，根据你给的模板，让它生成面试官问法 + 答案。</li><li>输出：保存到 Markdown 文件，直接放进你现在的文档库。</li></ul></li></ul></li></ul><blockquote><p>这一阶段不需要追求“系统设计很完美”，<strong>重点是把“人肉操作”变成“脚本 + 模型”的组合</strong>。</p></blockquote><hr><h2 id="_4-这一阶段的-合格线-与进阶建议" tabindex="-1">4. 这一阶段的“合格线”与进阶建议 <a class="header-anchor" href="#_4-这一阶段的-合格线-与进阶建议" aria-label="Permalink to “4. 这一阶段的“合格线”与进阶建议”">​</a></h2><p><strong>合格线（对你现阶段足够）：</strong></p><ul><li>能稳定用 1～2 个大模型来： <ul><li>写/改业务代码、解释报错。</li><li>帮你整理学习计划、总结笔记。</li><li>生成面试 Q&amp;A 草稿，再由你自己润色。</li></ul></li><li>至少有 1 个自己写的小脚本/工具接入了 API（如果你愿意做这一块）。</li></ul><p><strong>进阶建议（有空可以做）：</strong></p><ul><li>开始整理<strong>自己的 Prompt 模板库</strong>，按场景分类： <ul><li><code>面试准备 / 学习总结 / 代码重构 / 项目包装 / 简历优化 / 日常规划</code>。</li></ul></li><li>把你这套 Java 面试文档库和 LLM 结合起来，做一个<strong>“我的面试专属 ChatBot”</strong>（可以后续在 Agent 阶段实现）。</li></ul>',26)])])}const m=i(o,[["render",e]]);export{d as __pageData,m as default};
